#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e6+10;char s[N];
class SAM
{
	class node
	{
		public:int ch[26],len,fa;
		node(const int &L=0){memset(ch,0,sizeof(ch));fa=0;len=L;}
	};
	public:
	vector<node> t;int lst;
	void GetParentTree(vector<vector<int> > &G)//GPT(x
	{
		G.resize(t.size());
		for(unsigned i=1;i<t.size();++i)G[t[i].fa].push_back(i);
	}
	void extend(const int &c)
	{
		int p=lst,np=lst=t.size();
		t.push_back(node(t[p].len+1));
		for(;p&&!t[p].ch[c];p=t[p].fa)t[p].ch[c]=np;
 		if(!p)t[np].fa=1;
 		else
 		{
 			int v=t[p].ch[c];
 			if(t[v].len==t[p].len+1)t[np].fa=v;
 			else
 			{
 				int nv=t.size();t.push_back(t[v]);
 				t[nv].len=t[p].len+1;
 				for(;p&&t[p].ch[c]==v;p=t[p].fa)t[p].ch[c]=nv;
 				t[np].fa=t[v].fa=nv;
			}
		}
	}
	SAM(){t.assign(2,node());lst=1;}
	inline void clear(){t.assign(2,node());lst=1;}
	inline int next(int p,int c){return t[p].ch[c];}
	inline int Len(int p){return t[p].len;}
}sam;
vector<vector<int> > T;int siz[N];
long long ans;
inline void dfs(int u)
{
	for(int v:T[u]){dfs(v);siz[u]+=siz[v];}
	if(siz[u]>1)ans=max(ans,1ll*siz[u]*sam.Len(u));
}
int main()
{
	scanf("%s",s+1);
	int n=strlen(s+1);rep(1,n,i)sam.extend(s[i]-'a');
	sam.GetParentTree(T);
	int p=1;rep(1,n,i){p=sam.next(p,s[i]-'a');++siz[p];}
	dfs(1);printf("%lld\n",ans);

}
